import { makeUserService } from "../src/userService.js";

describe("makeUserService getUsers", () => {
  it("does not leak archived users into a picker call that excludes them", async () => {
    const loadUsers = async ({ includeArchived }) =>
      includeArchived ? ["alice", "bob", "archived-carol"] : ["alice", "bob"];

    const service = makeUserService(loadUsers);

    // Some view asks for archived users first, warming the cache.
    await service.getUsers({ team: "eng", includeArchived: true });

    // The people picker requests the same team without archived users.
    const picker = await service.getUsers({ team: "eng", includeArchived: false });

    expect(picker).toEqual(["alice", "bob"]);
  });
});

